import React from 'react';

const LiquiditySection = () => {
  return (
    <div className="space-y-8">
      <div>
        <h2 className="text-3xl font-bold text-white mb-6">Liquidity Provision Guide</h2>
        <p className="text-gray-300 text-lg leading-relaxed mb-8">
          Learn how to provide liquidity to trading pairs and earn fees on mochi. Liquidity provision is 
          a key component of DeFi that allows you to earn passive income while supporting the ecosystem.
        </p>
      </div>

      {/* What is Liquidity Provision */}
      <div>
        <h3 className="text-2xl font-bold text-white mb-6">What is Liquidity Provision?</h3>
        <div className="bg-gray-750 rounded-lg p-6 border border-gray-600">
          <p className="text-gray-300 mb-4">
            Liquidity provision is the process of depositing tokens into a trading pair to enable others to trade. 
            In return, you earn a portion of the trading fees generated by that pair.
          </p>
          <div className="grid md:grid-cols-3 gap-4">
            <div className="text-center p-4">
              <div className="text-2xl mb-2">💰</div>
              <h4 className="text-white font-semibold mb-2">Earn Fees</h4>
              <p className="text-gray-300 text-sm">Get a share of all trading fees</p>
            </div>
            <div className="text-center p-4">
              <div className="text-2xl mb-2">🌱</div>
              <h4 className="text-white font-semibold mb-2">Compound Growth</h4>
              <p className="text-gray-300 text-sm">Fees automatically reinvested</p>
            </div>
            <div className="text-center p-4">
              <div className="text-2xl mb-2">🔓</div>
              <h4 className="text-white font-semibold mb-2">Permissionless</h4>
              <p className="text-gray-300 text-sm">Anyone can provide liquidity</p>
            </div>
          </div>
        </div>
      </div>

      {/* How AMM Works */}
      <div>
        <h3 className="text-2xl font-bold text-white mb-6">How Automated Market Making (AMM) Works</h3>
        <div className="grid md:grid-cols-2 gap-6">
          <div className="bg-gray-750 rounded-lg p-6 border border-gray-600">
            <h4 className="text-lg font-semibold text-white mb-4">Constant Product Formula</h4>
            <p className="text-gray-300 mb-4">
              mochi uses the constant product formula: <code className="bg-gray-800 px-2 py-1 rounded">x * y = k</code>
            </p>
            <ul className="space-y-2 text-gray-300">
              <li>• <strong>x:</strong> Amount of token A in the pool</li>
              <li>• <strong>y:</strong> Amount of token B in the pool</li>
              <li>• <strong>k:</strong> Constant that must remain the same</li>
              <li>• Price is determined by the ratio of tokens</li>
            </ul>
          </div>

          <div className="bg-gray-750 rounded-lg p-6 border border-gray-600">
            <h4 className="text-lg font-semibold text-white mb-4">Price Impact</h4>
            <p className="text-gray-300 mb-4">
              The larger the trade relative to pool size, the more price impact it has.
            </p>
            <div className="space-y-2 text-sm text-gray-300">
              <div>• <strong>Small trades:</strong> Minimal price impact</div>
              <div>• <strong>Large trades:</strong> Higher price impact</div>
              <div>• <strong>More liquidity:</strong> Lower price impact</div>
              <div>• <strong>Less liquidity:</strong> Higher price impact</div>
            </div>
          </div>
        </div>
      </div>

      {/* Adding Liquidity */}
      <div>
        <h3 className="text-2xl font-bold text-white mb-6">Adding Liquidity</h3>
        <div className="space-y-6">
          <div className="bg-gray-750 rounded-lg p-6 border border-gray-600">
            <h4 className="text-lg font-semibold text-white mb-4">Step 1: Choose a Trading Pair</h4>
            <div className="space-y-3">
              <p className="text-gray-300">1. Navigate to the Liquidity page</p>
              <p className="text-gray-300">2. Select an existing pair or create a new one</p>
              <p className="text-gray-300">3. Consider the token combination and potential fees</p>
              <p className="text-gray-300">4. Check the current liquidity and trading volume</p>
            </div>
          </div>

          <div className="bg-gray-750 rounded-lg p-6 border border-gray-600">
            <h4 className="text-lg font-semibold text-white mb-4">Step 2: Provide Equal Value</h4>
            <div className="space-y-3">
              <p className="text-gray-300">1. Enter the amount of the first token</p>
              <p className="text-gray-300">2. The second token amount is calculated automatically</p>
              <p className="text-gray-300">3. Ensure you have sufficient balance of both tokens</p>
              <p className="text-gray-300">4. Review the pool share you'll receive</p>
            </div>
          </div>

          <div className="bg-gray-750 rounded-lg p-6 border border-gray-600">
            <h4 className="text-lg font-semibold text-white mb-4">Step 3: Confirm and Add</h4>
            <div className="space-y-3">
              <p className="text-gray-300">1. Review all transaction details</p>
              <p className="text-gray-300">2. Check gas fees and confirm the transaction</p>
              <p className="text-gray-300">3. Wait for confirmation on the blockchain</p>
              <p className="text-gray-300">4. Receive LP tokens representing your share</p>
            </div>
          </div>
        </div>
      </div>

      {/* Impermanent Loss */}
      <div>
        <h3 className="text-2xl font-bold text-white mb-6">Understanding Impermanent Loss</h3>
        <div className="bg-yellow-900/20 border border-yellow-500/30 rounded-lg p-6">
          <h4 className="text-lg font-semibold text-white mb-4">⚠️ What is Impermanent Loss?</h4>
          <p className="text-gray-300 mb-4">
            Impermanent loss occurs when the price ratio of your deposited tokens changes. 
            This can result in fewer tokens when you withdraw compared to if you had just held them.
          </p>
          
          <div className="grid md:grid-cols-2 gap-6">
            <div>
              <h5 className="text-white font-semibold mb-2">When It Occurs:</h5>
              <ul className="space-y-1 text-gray-300 text-sm">
                <li>• Token prices move in opposite directions</li>
                <li>• One token significantly outperforms the other</li>
                <li>• High volatility in either token</li>
                <li>• Large price swings during your position</li>
              </ul>
            </div>
            
            <div>
              <h5 className="text-white font-semibold mb-2">Mitigation Strategies:</h5>
              <ul className="space-y-1 text-gray-300 text-sm">
                <li>• Choose correlated token pairs</li>
                <li>• Provide liquidity to stable pairs (e.g., USDC/USDT)</li>
                <li>• Monitor and rebalance positions</li>
                <li>• Consider impermanent loss protection</li>
              </ul>
            </div>
          </div>
        </div>
      </div>

      {/* Managing Positions */}
      <div>
        <h3 className="text-2xl font-bold text-white mb-6">Managing Your Liquidity Positions</h3>
        <div className="grid md:grid-cols-2 gap-6">
          <div className="bg-gray-750 rounded-lg p-6 border border-gray-600">
            <h4 className="text-lg font-semibold text-white mb-4">Monitoring Performance</h4>
            <ul className="space-y-2 text-gray-300">
              <li>• Track your LP token balance</li>
              <li>• Monitor earned fees and APY</li>
              <li>• Check impermanent loss calculations</li>
              <li>• Review trading volume and liquidity depth</li>
              <li>• Set up alerts for significant changes</li>
            </ul>
          </div>

          <div className="bg-gray-750 rounded-lg p-6 border border-gray-600">
            <h4 className="text-lg font-semibold text-white mb-4">Collecting Fees</h4>
            <ul className="space-y-2 text-gray-300">
              <li>• Fees are automatically added to your position</li>
              <li>• You can compound by adding more liquidity</li>
              <li>• Withdraw fees by removing a portion of liquidity</li>
              <li>• Consider gas costs when collecting fees</li>
              <li>• Monitor fee accumulation over time</li>
            </ul>
          </div>
        </div>
      </div>

      {/* Removing Liquidity */}
      <div>
        <h3 className="text-2xl font-bold text-white mb-6">Removing Liquidity</h3>
        <div className="space-y-4">
          <div className="bg-gray-750 rounded-lg p-6 border border-gray-600">
            <h4 className="text-lg font-semibold text-white mb-4">Step-by-Step Process</h4>
            <div className="space-y-3">
              <p className="text-gray-300">1. Navigate to your liquidity positions</p>
              <p className="text-gray-300">2. Select the position you want to remove</p>
              <p className="text-gray-300">3. Choose the percentage to remove (or all)</p>
              <p className="text-gray-300">4. Review the tokens you'll receive</p>
              <p className="text-gray-300">5. Confirm the transaction and pay gas fees</p>
            </div>
          </div>

          <div className="bg-blue-900/20 border border-blue-500/30 rounded-lg p-6">
            <h4 className="text-lg font-semibold text-white mb-4">💡 Tips for Removing Liquidity</h4>
            <ul className="space-y-2 text-gray-300">
              <li>• Consider gas costs when removing small amounts</li>
              <li>• Check current token prices before removing</li>
              <li>• Remove during low gas periods if possible</li>
              <li>• Consider partial removals to maintain some exposure</li>
              <li>• Review impermanent loss before removing</li>
            </ul>
          </div>
        </div>
      </div>

      {/* Best Practices */}
      <div>
        <h3 className="text-2xl font-bold text-white mb-6">Liquidity Provision Best Practices</h3>
        <div className="grid md:grid-cols-2 gap-6">
          <div className="bg-green-900/20 border border-green-500/30 rounded-lg p-6">
            <h4 className="text-lg font-semibold text-white mb-4">✅ Recommended Strategies</h4>
            <ul className="space-y-2 text-gray-300">
              <li>• Start with stable pairs (USDC/USDT)</li>
              <li>• Diversify across multiple pairs</li>
              <li>• Monitor positions regularly</li>
              <li>• Reinvest fees for compound growth</li>
              <li>• Choose pairs with good trading volume</li>
              <li>• Consider impermanent loss protection</li>
            </ul>
          </div>

          <div className="bg-red-900/20 border border-red-500/30 rounded-lg p-6">
            <h4 className="text-lg font-semibold text-white mb-4">❌ Avoid These Mistakes</h4>
            <ul className="space-y-2 text-gray-300">
              <li>• Don't provide liquidity to unknown tokens</li>
              <li>• Don't ignore impermanent loss risks</li>
              <li>• Don't put all funds in one pair</li>
              <li>• Don't forget to monitor positions</li>
              <li>• Don't provide liquidity without understanding</li>
              <li>• Don't ignore gas costs for small positions</li>
            </ul>
          </div>
        </div>
      </div>

      {/* Risk Management */}
      <div>
        <h3 className="text-2xl font-bold text-white mb-6">Risk Management</h3>
        <div className="bg-gray-750 rounded-lg p-6 border border-gray-600">
          <h4 className="text-lg font-semibold text-white mb-4">Key Risks to Consider</h4>
          <div className="grid md:grid-cols-2 gap-6">
            <div>
              <h5 className="text-white font-semibold mb-2">Market Risks:</h5>
              <ul className="space-y-1 text-gray-300 text-sm">
                <li>• Impermanent loss</li>
                <li>• Token price volatility</li>
                <li>• Market downturns</li>
                <li>• Liquidity drying up</li>
              </ul>
            </div>
            
            <div>
              <h5 className="text-white font-semibold mb-2">Technical Risks:</h5>
              <ul className="space-y-1 text-gray-300 text-sm">
                <li>• Smart contract vulnerabilities</li>
                <li>• Gas fee fluctuations</li>
                <li>• Network congestion</li>
                <li>• Front-running attacks</li>
              </ul>
            </div>
          </div>
          
          <div className="mt-6 p-4 bg-blue-900/20 border border-blue-500/30 rounded-lg">
            <h5 className="text-white font-semibold mb-2">Risk Mitigation:</h5>
            <ul className="space-y-1 text-gray-300 text-sm">
              <li>• Only invest what you can afford to lose</li>
              <li>• Diversify across multiple pairs and networks</li>
              <li>• Use open source smart contracts</li>
              <li>• Monitor positions regularly</li>
              <li>• Have an exit strategy</li>
            </ul>
          </div>
        </div>
      </div>
    </div>
  );
};

export default LiquiditySection; 